DROP TABLE IF EXISTS `psm`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `psm` (
  `psm_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `detail` text DEFAULT NULL,
  `enabled` tinyint(4) NOT NULL DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `type` enum('template','submission') NOT NULL DEFAULT 'submission',
  `template_psm_id` bigint(20) unsigned DEFAULT NULL,
  `created_by` bigint(20) unsigned DEFAULT NULL,
  `is_locked` tinyint(1) NOT NULL DEFAULT 0,
  `identifier` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`psm_id`),
  UNIQUE KEY `psm_identifier_unique` (`identifier`),
  KEY `psm_created_by_foreign` (`created_by`),
  KEY `psm_is_locked_index` (`is_locked`),
  CONSTRAINT `psm_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=83 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
