  KEY `psm_value_psm_var_id_foreign` (`psm_var_id`),
  CONSTRAINT `psm_value_psm_id_foreign` FOREIGN KEY (`psm_id`) REFERENCES `psm` (`psm_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `psm_value_psm_var_id_foreign` FOREIGN KEY (`psm_var_id`) REFERENCES `psm_variable` (`psm_var_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1555 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
